// [[Rcpp::export]]
SEXP C_torch_linalg_cholesky_ex(at::Tensor self, bool upper, bool check_errors) {
    auto result = at::linalg_cholesky_ex(self, upper, check_errors);
    SEXP out = PROTECT(Rf_allocVector(VECSXP, 2));
    SET_VECTOR_ELT(out, 0, Rcpp::wrap(std::get<0>(result)));
    SET_VECTOR_ELT(out, 1, Rcpp::wrap(std::get<1>(result)));
    SEXP names = PROTECT(Rf_allocVector(STRSXP, 2));
    SET_STRING_ELT(names, 0, Rf_mkChar("L"));
    SET_STRING_ELT(names, 1, Rf_mkChar("info"));
    Rf_setAttrib(out, R_NamesSymbol, names);
    UNPROTECT(2);
    return out;
}

